sys_variable_value.value:
(function(outputs, steps, params, stepResult, assertEqual) {
    var tableName = 'x_1839224_chroma_0_chromatech_sold_products'; // Replace with actual table name
    var sectionName = 'Dates';
    var errors = [];

    // 1. Verify Form Section exists
    var grSection = new GlideRecord('sys_ui_section');
    grSection.addQuery('name', tableName);
    grSection.addQuery('caption', sectionName);
    grSection.query();

    if (!grSection.next()) {
        stepResult.setFailed();
        stepResult.setOutputMessage("Failure: Form section '" + sectionName + "' not found on table " + tableName);
        return false;
    }

    var sectionID = grSection.getUniqueValue();

    // 2. Verify 2-Column Format (Checking for a Split/Spacer element)
    var grElements = new GlideRecord('sys_ui_element');
    grElements.addQuery('sys_ui_section', sectionID);
    grElements.addQuery('type', '.split'); // A 'split' type indicates a 2-column layout
    grElements.query();

    if (grElements.getRowCount() === 0) {
        errors.push("Layout Error: Section '" + sectionName + "' is not in 2-column format (missing split/spacer).");
    }

    // 3. Verify Fields in this Section
    var expectedFields = [
        'date_sold_on',
        'manufacturing_date',
        'warranty_extending_date',
        'warranty_expiring_at'
    ];

    expectedFields.forEach(function(field) {
        var grField = new GlideRecord('sys_ui_element');
        grField.addQuery('sys_ui_section', sectionID);
        grField.addQuery('element', field);
        grField.query();
        
        if (!grField.hasNext()) {
            errors.push("Field Error: '" + field + "' is missing from the '" + sectionName + "' section.");
        }
    });

    // Final Result
    if (errors.length === 0) {
        stepResult.setSuccess();
        stepResult.setOutputMessage("Success: Section '" + sectionName + "' verified with 2-column layout and all fields.");
        return true;
    } else {
        stepResult.setFailed();
        stepResult.setOutputMessage("Failure:\n" + errors.join('\n'));
        return false;
    }

})(outputs, steps, params, stepResult, assertEqual);
